import React from "react"
import { Link } from "gatsby"
import styled from 'styled-components';

const Jump = styled(Link)`
    font-size: 13px;
`

const Prev = styled(Jump)`
  float: left;
`;

const Next = styled(Jump)`
  float: right;
`

const Pagination = ({
    prevPagePath,
    nextPagePath,
    hasNextPage,
    hasPrevPage
}) => {
  return (
    <nav>
        { hasPrevPage &&
            <Prev to={prevPagePath}>← Newer Posts</Prev>
        }
        { hasNextPage &&
            <Next to={nextPagePath}>Older Posts →</Next>
        }
    </nav>
  )
}

export default Pagination
